[
  {
    "id": "lib_push_hypertrophy_gym",
    "title": "Push Day - Hipertrofia",
    "subtitle": "Peito, Ombros e Tríceps para ganho de massa",
    "goal": "hypertrophy",
    "structure": "fullGym",
    "estimated_duration_minutes": 55,
    "intensity": "high",
    "exercises": [
      {
        "exercise": {
          "id": "barbell_bench_press",
          "name": "Barbell Bench Press",
          "main_muscle": "chest",
          "equipment": "barbell",
          "instructions": [
            "Deite no banco com os pés firmemente apoiados no chão",
            "Pegada um pouco mais larga que a largura dos ombros",
            "Desça a barra controladamente até tocar o peito",
            "Empurre explosivamente mantendo as escápulas retraídas"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 6,
        "reps_upper": 8,
        "rest_interval": 120,
        "tip": "Mantenha as escápulas retraídas e o peito projetado durante todo movimento"
      },
      {
        "exercise": {
          "id": "incline_dumbbell_press",
          "name": "Incline Dumbbell Press",
          "main_muscle": "chest",
          "equipment": "dumbbell",
          "instructions": [
            "Ajuste o banco em 30-45 graus de inclinação",
            "Inicie com os halteres na altura dos ombros",
            "Empurre para cima unindo os halteres no topo",
            "Desça controladamente sentindo o alongamento"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 8,
        "reps_upper": 10,
        "rest_interval": 90,
        "tip": "Não deixe os cotovelos abrirem demais para proteger os ombros"
      },
      {
        "exercise": {
          "id": "cable_crossover",
          "name": "Cable Crossover",
          "main_muscle": "chest",
          "equipment": "cable",
          "instructions": [
            "Posicione as polias na altura mais alta",
            "Dê um passo à frente para criar tensão",
            "Una as mãos à frente do corpo contraindo o peitoral",
            "Retorne controladamente mantendo a tensão"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Foque na contração do peitoral no pico do movimento"
      },
      {
        "exercise": {
          "id": "seated_dumbbell_shoulder_press",
          "name": "Seated Dumbbell Shoulder Press",
          "main_muscle": "shoulders",
          "equipment": "dumbbell",
          "instructions": [
            "Sente com as costas apoiadas no banco reto",
            "Inicie com os halteres na altura dos ombros",
            "Empurre para cima até quase estender os braços",
            "Desça controladamente até a posição inicial"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 8,
        "reps_upper": 10,
        "rest_interval": 90,
        "tip": "Mantenha o core ativado para estabilizar a coluna"
      },
      {
        "exercise": {
          "id": "lateral_raise",
          "name": "Dumbbell Lateral Raise",
          "main_muscle": "shoulders",
          "equipment": "dumbbell",
          "instructions": [
            "Fique em pé com halteres ao lado do corpo",
            "Levante os braços lateralmente até a altura dos ombros",
            "Mantenha leve flexão dos cotovelos",
            "Desça controladamente sem balançar"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Use pesos moderados para manter a técnica perfeita"
      },
      {
        "exercise": {
          "id": "tricep_rope_pushdown",
          "name": "Triceps Rope Pushdown",
          "main_muscle": "triceps",
          "equipment": "cable",
          "instructions": [
            "Segure a corda com pegada neutra",
            "Mantenha os cotovelos fixos ao lado do corpo",
            "Estenda os braços separando as pontas da corda",
            "Retorne controladamente mantendo a tensão"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Separe as pontas da corda ao final para maior contração"
      },
      {
        "exercise": {
          "id": "pec_deck_fly",
          "name": "Pec Deck Fly",
          "main_muscle": "chest",
          "equipment": "machine",
          "instructions": [
            "Ajuste o banco na altura do peito",
            "Segure as alavancas com os cotovelos ligeiramente flexionados",
            "Traga as mãos em direção ao centro do corpo",
            "Abra os braços de forma controlada"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Foque no alongamento do peitoral na abertura"
      },
      {
        "exercise": {
          "id": "overhead_tricep_extension",
          "name": "Dumbbell Overhead Triceps Extension",
          "main_muscle": "triceps",
          "equipment": "dumbbell",
          "instructions": [
            "Fique em pé segurando um halter com as duas mãos",
            "Posicione o halter atrás da cabeça",
            "Estenda os cotovelos para cima",
            "Desça controladamente sem mover os cotovelos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 60,
        "tip": "Mantenha os cotovelos apontados para frente"
      }
    ]
  },
  {
    "id": "lib_pull_hypertrophy_gym",
    "title": "Pull Day - Hipertrofia",
    "subtitle": "Costas e Bíceps para um dorsal definido",
    "goal": "hypertrophy",
    "structure": "fullGym",
    "estimated_duration_minutes": 55,
    "intensity": "high",
    "exercises": [
      {
        "exercise": {
          "id": "lat_pulldown",
          "name": "Lat Pulldown",
          "main_muscle": "back",
          "equipment": "cable",
          "instructions": [
            "Sente-se com as coxas travadas sob o apoio",
            "Segure a barra com pegada pronada mais larga que os ombros",
            "Puxe a barra até o peito, contraindo as escápulas",
            "Retorne controladamente à posição inicial"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 8,
        "reps_upper": 12,
        "rest_interval": 90,
        "tip": "Inicie o movimento puxando com as costas, não com os braços"
      },
      {
        "exercise": {
          "id": "barbell_row",
          "name": "Barbell Bent Over Row",
          "main_muscle": "back",
          "equipment": "barbell",
          "instructions": [
            "Incline o tronco cerca de 45 graus, coluna neutra",
            "Segure a barra com pegada pronada na largura dos ombros",
            "Puxe a barra em direção ao abdômen baixo",
            "Desça controladamente mantendo a postura"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 8,
        "reps_upper": 10,
        "rest_interval": 90,
        "tip": "Mantenha o core contraído para proteger a lombar"
      },
      {
        "exercise": {
          "id": "seated_cable_row",
          "name": "Seated Cable Row",
          "main_muscle": "back",
          "equipment": "cable",
          "instructions": [
            "Sente com os pés apoiados e joelhos levemente flexionados",
            "Segure o triângulo ou barra com braços estendidos",
            "Puxe em direção ao abdômen, abrindo o peito",
            "Retorne controladamente sem perder a postura"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 75,
        "tip": "Foque em apertar as escápulas no final do movimento"
      },
      {
        "exercise": {
          "id": "face_pull",
          "name": "Face Pull",
          "main_muscle": "shoulders",
          "equipment": "cable",
          "instructions": [
            "Ajuste a polia na altura do rosto",
            "Segure a corda com pegada neutra",
            "Puxe em direção ao rosto separando as mãos",
            "Foque na rotação externa dos ombros"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 15,
        "reps_upper": 20,
        "rest_interval": 60,
        "tip": "Excelente para saúde dos ombros e postura"
      },
      {
        "exercise": {
          "id": "barbell_curl",
          "name": "Barbell Curl",
          "main_muscle": "biceps",
          "equipment": "barbell",
          "instructions": [
            "Fique em pé com a barra e pegada supinada",
            "Mantenha os cotovelos fixos ao lado do corpo",
            "Flexione os braços trazendo a barra aos ombros",
            "Desça controladamente sem balançar"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 60,
        "tip": "Controle a fase negativa para maior hipertrofia"
      },
      {
        "exercise": {
          "id": "hammer_curl",
          "name": "Dumbbell Hammer Curl",
          "main_muscle": "biceps",
          "equipment": "dumbbell",
          "instructions": [
            "Segure os halteres com pegada neutra (palmas voltadas)",
            "Mantenha os cotovelos junto ao corpo",
            "Flexione alternadamente ou simultaneamente",
            "Desça controladamente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 60,
        "tip": "Trabalha braquial e braquiorradial além do bíceps"
      },
      {
        "exercise": {
          "id": "back_extension",
          "name": "Back Extension",
          "main_muscle": "back",
          "equipment": "machine",
          "instructions": [
            "Ajuste a máquina para que o quadril seja o ponto de pivot",
            "Coloque os pés sob o apoio",
            "Incline o tronco para frente com coluna neutra",
            "Estenda para trás contraindo as costas e glúteos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Ótimo para fortalecer e proteger a coluna"
      },
      {
        "exercise": {
          "id": "cable_preacher_curl",
          "name": "Cable Preacher Curl",
          "main_muscle": "biceps",
          "equipment": "cable",
          "instructions": [
            "Ajuste o banco preacher e segure a barra com pegada supinada",
            "Mantenha os cotovelos fixos sobre o banco",
            "Flexione os braços trazendo a barra ao queixo",
            "Desça controladamente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Ótimo isolamento para o bíceps"
      }
    ]
  },
  {
    "id": "lib_legs_hypertrophy_gym",
    "title": "Leg Day - Hipertrofia",
    "subtitle": "Quadríceps, Glúteos e Posteriores",
    "goal": "hypertrophy",
    "structure": "fullGym",
    "estimated_duration_minutes": 60,
    "intensity": "high",
    "exercises": [
      {
        "exercise": {
          "id": "barbell_squat",
          "name": "Barbell Squat",
          "main_muscle": "quads",
          "equipment": "barbell",
          "instructions": [
            "Posicione a barra no trapézio alto",
            "Pés na largura dos ombros, pontas levemente para fora",
            "Desça até as coxas ficarem paralelas ao chão",
            "Suba explosivamente mantendo os joelhos alinhados"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 6,
        "reps_upper": 8,
        "rest_interval": 150,
        "tip": "Rei dos exercícios - mantenha a técnica perfeita"
      },
      {
        "exercise": {
          "id": "leg_press",
          "name": "Leg Press",
          "main_muscle": "quads",
          "equipment": "machine",
          "instructions": [
            "Ajuste o banco e posicione os pés na plataforma",
            "Destrave o peso e desça controladamente",
            "Desça até 90 graus de flexão nos joelhos",
            "Empurre sem travar completamente os joelhos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 90,
        "tip": "Varie a posição dos pés para diferentes estímulos"
      },
      {
        "exercise": {
          "id": "romanian_deadlift",
          "name": "Barbell Romanian Deadlift",
          "main_muscle": "hamstrings",
          "equipment": "barbell",
          "instructions": [
            "Segure a barra com pegada pronada",
            "Mantenha os joelhos levemente flexionados",
            "Incline o tronco empurrando o quadril para trás",
            "Desça até sentir alongamento nos posteriores"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 12,
        "rest_interval": 90,
        "tip": "Mantenha a barra próxima às pernas durante todo o movimento"
      },
      {
        "exercise": {
          "id": "leg_curl_lying",
          "name": "Lying Leg Curl",
          "main_muscle": "hamstrings",
          "equipment": "machine",
          "instructions": [
            "Deite de bruços com os calcanhares sob o rolo",
            "Flexione os joelhos trazendo o rolo em direção aos glúteos",
            "Segure por 1 segundo no pico da contração",
            "Retorne controladamente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Evite levantar o quadril durante o movimento"
      },
      {
        "exercise": {
          "id": "leg_extension",
          "name": "Leg Extension",
          "main_muscle": "quads",
          "equipment": "machine",
          "instructions": [
            "Ajuste o encosto e o rolo na altura dos tornozelos",
            "Estenda os joelhos elevando o rolo",
            "Segure por 1 segundo no topo",
            "Desça controladamente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 60,
        "tip": "Excelente para finalizar o treino de quadríceps"
      },
      {
        "exercise": {
          "id": "standing_calf_raise",
          "name": "Standing Calf Raise",
          "main_muscle": "calves",
          "equipment": "machine",
          "instructions": [
            "Posicione os ombros sob os apoios",
            "Fique na ponta dos pés no step",
            "Desça os calcanhares abaixo do step",
            "Suba até a máxima extensão dos tornozelos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 15,
        "reps_upper": 20,
        "rest_interval": 45,
        "tip": "Faça a amplitude completa do movimento"
      },
      {
        "exercise": {
          "id": "leg_press_wide",
          "name": "Wide Stance Leg Press",
          "main_muscle": "glutes",
          "equipment": "machine",
          "instructions": [
            "Posicione os pés na parte superior da plataforma",
            "Mantenha os pés afastados além da largura do quadril",
            "Desça controladamente até 90 graus",
            "Empurre para cima focando nos glúteos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 90,
        "tip": "Ativa mais os glúteos que os quadríceps"
      },
      {
        "exercise": {
          "id": "hack_squat",
          "name": "Hack Squat",
          "main_muscle": "quads",
          "equipment": "machine",
          "instructions": [
            "Posicione as costas contra o encosto",
            "Pés na plataforma na altura dos ombros",
            "Desça dobrando os joelhos mantendo as costas apoiadas",
            "Suba estendendo as pernas completamente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 15,
        "rest_interval": 90,
        "tip": "Ótima alternativa ao agachamento livre"
      }
    ]
  },
  {
    "id": "lib_fullbody_conditioning_home",
    "title": "Full Body Funcional",
    "subtitle": "Circuito de peso corporal para condicionamento",
    "goal": "conditioning",
    "structure": "bodyweight",
    "estimated_duration_minutes": 35,
    "intensity": "moderate",
    "exercises": [
      {
        "exercise": {
          "id": "burpee",
          "name": "Burpee",
          "main_muscle": "fullBody",
          "equipment": "bodyweight",
          "instructions": [
            "Comece em pé, agache e coloque as mãos no chão",
            "Salte os pés para trás entrando em prancha",
            "Faça uma flexão (opcional)",
            "Salte os pés de volta e pule verticalmente"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 4,
        "reps_lower": 8,
        "reps_upper": 12,
        "rest_interval": 45,
        "tip": "Mantenha um ritmo constante, qualidade sobre velocidade"
      },
      {
        "exercise": {
          "id": "push_up",
          "name": "Push Up",
          "main_muscle": "chest",
          "equipment": "bodyweight",
          "instructions": [
            "Posicione as mãos na largura dos ombros",
            "Mantenha o corpo em linha reta",
            "Desça o peito até quase tocar o chão",
            "Empurre de volta à posição inicial"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 12,
        "reps_upper": 20,
        "rest_interval": 45,
        "tip": "Mantenha o core contraído durante todo o movimento"
      },
      {
        "exercise": {
          "id": "bodyweight_squat",
          "name": "Bodyweight Squat",
          "main_muscle": "quads",
          "equipment": "bodyweight",
          "instructions": [
            "Pés na largura dos ombros",
            "Desça como se fosse sentar em uma cadeira",
            "Mantenha o peito aberto e joelhos alinhados",
            "Suba contraindo glúteos"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 15,
        "reps_upper": 20,
        "rest_interval": 45,
        "tip": "Distribua o peso nos calcanhares"
      },
      {
        "exercise": {
          "id": "mountain_climber",
          "name": "Mountain Climber",
          "main_muscle": "core",
          "equipment": "bodyweight",
          "instructions": [
            "Comece em posição de prancha alta",
            "Traga um joelho em direção ao peito",
            "Alterne as pernas rapidamente",
            "Mantenha o quadril baixo e alinhado"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 20,
        "reps_upper": 30,
        "rest_interval": 45,
        "tip": "Controle o movimento, não deixe o quadril subir"
      },
      {
        "exercise": {
          "id": "plank",
          "name": "Plank",
          "main_muscle": "core",
          "equipment": "bodyweight",
          "instructions": [
            "Apoie os antebraços e pontas dos pés no chão",
            "Mantenha o corpo em linha reta",
            "Contraia o abdômen e glúteos",
            "Segure a posição pelo tempo indicado"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 30,
        "reps_upper": 60,
        "rest_interval": 30,
        "tip": "Respire normalmente, não prenda a respiração"
      },
      {
        "exercise": {
          "id": "jumping_jacks",
          "name": "Jumping Jack",
          "main_muscle": "fullBody",
          "equipment": "bodyweight",
          "instructions": [
            "Comece em pé com braços ao lado do corpo",
            "Salte abrindo pernas e levantando braços",
            "Retorne à posição inicial com outro salto",
            "Mantenha ritmo constante"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 30,
        "reps_upper": 50,
        "rest_interval": 30,
        "tip": "Ótimo para aquecimento e cardio"
      },
      {
        "exercise": {
          "id": "push_up_wide",
          "name": "Wide Grip Push Up",
          "main_muscle": "chest",
          "equipment": "bodyweight",
          "instructions": [
            "Posicione as mãos mais afastadas que a largura dos ombros",
            "Mantenha o corpo em linha reta",
            "Desça o peito até quase tocar o chão",
            "Empurre de volta mantendo a postura"
          ],
          "media": {
            "image_url": null,
            "gif_url": null
          }
        },
        "sets": 3,
        "reps_lower": 10,
        "reps_upper": 15,
        "rest_interval": 45,
        "tip": "Mais fácil que a pegada normal, maior ativação de peito"
      },
      {
        "exercise": {
          "id": "tricep_dips_bodyweight",
          "name": "Triceps Dip",
