13→struct ExerciseImageView: View {
14→    let exerciseId: String
15→    let imageIndex: Int
16→    var cornerRadius: CGFloat = 12
17→
18→    @State private var image: UIImage?
19→    @State private var isLoading = true
20→
21→    var body: some View {
22→        Group {
23→            if let image {
24→                Image(uiImage: image)
25→                    .resizable()
26→                    .aspectRatio(contentMode: .fill)
27→            } else if isLoading {
28→                ZStack {
29→                    RoundedRectangle(cornerRadius: cornerRadius)
30→                        .fill(FitTodayColor.surface)
31→                    ProgressView()
32→                        .tint(FitTodayColor.brandSecondary)
33→                }
34→            } else {
35→                ZStack {
36→                    RoundedRectangle(cornerRadius: cornerRadius)
37→                        .fill(FitTodayColor.surface)
38→                    Image(systemName: "figure.strengthtraining.traditional")
39→                        .font(.system(size: 40))
40→                        .foregroundStyle(FitTodayColor.textTertiary)
41→                }
42→            }
43→        }
44→        .clipShape(RoundedRectangle(cornerRadius: cornerRadius))
45→        .task(id: "\(exerciseId)_\(imageIndex)") {
46→            isLoading = true
47→            image = await ExerciseImageCache.shared.image(for: exerciseId, imageIndex: imageIndex)
48→            isLoading = false
49→        }
50→    }
51→}
