 1→//
 2→//  ExerciseAnimatedView.swift
 3→//  FitToday
 4→//
 5→//  Created by Claude on 03/03/26.
 6→//
 7→
 8→import Combine
 9→import SwiftUI
10→import UIKit
11→
12→/// Alternates between image 0 and image 1 every 1.2s to simulate a GIF.
13→/// Falls back to a static image if only image 0 exists.
14→/// Timer stops when the view disappears to prevent memory leaks.
15→struct ExerciseAnimatedView: View {
16→    let exerciseId: String
17→    var cornerRadius: CGFloat = 12
18→
19→    @State private var image0: UIImage?
20→    @State private var image1: UIImage?
21→    @State private var showingIndex0 = true
22→    @State private var isLoaded = false
23→
24→    private let timer = Timer.publish(every: 1.2, on: .main, in: .common)
25→    @State private var timerCancellable: Cancellable?
26→
27→    var body: some View {
28→        Group {
29→            if !isLoaded {
30→                ZStack {
31→                    RoundedRectangle(cornerRadius: cornerRadius)
32→                        .fill(FitTodayColor.surface)
33→                    ProgressView()
34→                        .tint(FitTodayColor.brandSecondary)
35→                }
36→            } else if let currentImage {
37→                Image(uiImage: currentImage)
38→                    .resizable()
39→                    .aspectRatio(contentMode: .fill)
40→                    .animation(.easeInOut(duration: 0.3), value: showingIndex0)
41→            } else {
42→                ZStack {
43→                    RoundedRectangle(cornerRadius: cornerRadius)
44→                        .fill(FitTodayColor.surface)
45→                    Image(systemName: "figure.strengthtraining.traditional")
46→                        .font(.system(size: 40))
47→                        .foregroundStyle(FitTodayColor.textTertiary)
48→                }
49→            }
50→        }
51→        .clipShape(RoundedRectangle(cornerRadius: cornerRadius))
52→        .task(id: exerciseId) {
53→            await loadImages()
54→        }
55→        .onAppear { startTimer() }
56→        .onDisappear { stopTimer() }
57→    }
58→
59→    private var currentImage: UIImage? {
60→        if showingIndex0 {
61→            return image0
62→        }
63→        return image1 ?? image0
64→    }
65→
66→    private func loadImages() async {
67→        image0 = await ExerciseImageCache.shared.image(for: exerciseId, imageIndex: 0)
68→        image1 = await ExerciseImageCache.shared.image(for: exerciseId, imageIndex: 1)
69→        isLoaded = true
70→        if image1 != nil {
71→            startTimer()
72→        }
73→    }
74→
75→    private func startTimer() {
76→        guard timerCancellable == nil else { return }
77→        timerCancellable = timer.autoconnect().sink { _ in
78→            showingIndex0.toggle()
79→        }
80→    }
81→
82→    private func stopTimer() {
83→        timerCancellable?.cancel()
84→        timerCancellable = nil
85→    }
86→}
