  1→//
  2→//  FirestoreProgramWorkoutRepository.swift
  3→//  FitToday
  4→//
  5→//  Loads catalog exercises for program workouts via ExerciseServiceProtocol.
  6→//  Primary implementation for loading program workout exercises.
  7→//
  8→
  9→import Foundation
 10→
 11→/// Repository that loads exercises from the Firestore catalog for program workouts.
 12→actor FirestoreProgramWorkoutRepository: ProgramWorkoutRepository {
 13→    private let exerciseService: ExerciseServiceProtocol
 14→    private let storage: UserDefaults
 15→    private let encoder = JSONEncoder()
 16→    private let decoder = JSONDecoder()
 17→
 18→    /// Cache: [categoryName: [CatalogExercise]]
 19→    private var exerciseCache: [String: [CatalogExercise]] = [:]
 20→    private var exerciseByIdCache: [String: CatalogExercise] = [:]
 21→
 22→    init(exerciseService: ExerciseServiceProtocol, storage: UserDefaults = .standard) {
 23→        self.exerciseService = exerciseService
 24→        self.storage = storage
 25→    }
 26→
 27→    // MARK: - ProgramWorkoutRepository
 28→
 29→    func loadWorkoutExercises(templateId: String, exerciseCount: Int = 8) async throws -> [CatalogExercise] {
 30→        guard let templateType = WorkoutTemplateType.from(templateId: templateId) else {
 31→            return try await loadExercisesForCategories(["chest", "back", "legs", "core"], count: exerciseCount)
 32→        }
 33→
 34→        let categoryNames = templateType.categoryNames
 35→        guard !categoryNames.isEmpty else {
 36→            throw ProgramWorkoutError.noCategories
 37→        }
 38→
 39→        return try await loadExercisesForCategories(categoryNames, count: exerciseCount)
 40→    }
 41→
 42→    func saveCustomization(programId: String, workoutId: String, exerciseIds: [String], order: [Int]) async throws {
 43→        let customization = WorkoutCustomization(
 44→            programId: programId,
 45→            workoutId: workoutId,
 46→            exerciseIds: exerciseIds,
 47→            order: order,
 48→            updatedAt: Date()
 49→        )
 50→
 51→        let data = try encoder.encode(customization)
 52→        storage.set(data, forKey: customization.storageKey)
 53→    }
 54→
 55→    func loadCustomization(programId: String, workoutId: String) async throws -> WorkoutCustomization? {
 56→        let key = "workout_customization_\(programId)_\(workoutId)"
 57→        guard let data = storage.data(forKey: key) else { return nil }
 58→
 59→        do {
 60→            return try decoder.decode(WorkoutCustomization.self, from: data)
 61→        } catch {
 62→            return nil
 63→        }
 64→    }
 65→
 66→    func fetchExercisesByIds(_ ids: [String]) async throws -> [CatalogExercise] {
 67→        var exercises: [CatalogExercise] = []
 68→
 69→        for id in ids {
 70→            if let cached = exerciseByIdCache[id] {
 71→                exercises.append(cached)
 72→            } else if let exercise = try await exerciseService.fetchExercise(id: id) {
 73→                exerciseByIdCache[id] = exercise
 74→                exercises.append(exercise)
 75→            }
 76→        }
 77→
 78→        return exercises
 79→    }
 80→
 81→    // MARK: - Private Helpers
 82→
 83→    private func loadExercisesForCategories(_ categoryNames: [String], count: Int) async throws -> [CatalogExercise] {
 84→        var allExercises: [CatalogExercise] = []
 85→        let exercisesPerCategory = max(1, count / categoryNames.count)
 86→
 87→        for categoryName in categoryNames {
 88→            let exercises = try await loadExercisesForCategory(categoryName)
 89→            let selected = exercises.shuffled().prefix(exercisesPerCategory + 2)
 90→            allExercises.append(contentsOf: selected)
 91→        }
 92→
 93→        let result = Array(allExercises.shuffled().prefix(count))
 94→
 95→        if result.isEmpty {
 96→            throw ProgramWorkoutError.exercisesNotFound
 97→        }
 98→
 99→        return result
100→    }
101→
102→    private func loadExercisesForCategory(_ categoryName: String) async throws -> [CatalogExercise] {
103→        if let cached = exerciseCache[categoryName], !cached.isEmpty {
104→            return cached
105→        }
106→
107→        do {
108→            let exercises = try await exerciseService.fetchExercises(
109→                language: .portuguese,
110→                category: categoryName,
111→                equipment: nil,
112→                limit: 50
113→            )
114→
115→            exerciseCache[categoryName] = exercises
116→            for exercise in exercises {
117→                exerciseByIdCache[exercise.id] = exercise
118→            }
119→
120→            return exercises
121→        } catch {
122→            throw ProgramWorkoutError.serviceError(error)
123→        }
124→    }
125→}
