//
//  FirestoreExerciseService.swift
//  FitToday
//
//  Fetches exercises from the Firestore catalog collection.
//  Primary exercise data source for the app.
//

import Foundation
import FirebaseFirestore

/// Firestore-backed exercise service.
actor FirestoreExerciseService: ExerciseServiceProtocol {
    private let db = Firestore.firestore()
    private let collectionName = "exercises"

    /// In-memory cache: [exerciseId: CatalogExercise]
    private var cache: [String: CatalogExercise] = [:]

    // MARK: - ExerciseServiceProtocol

    func fetchExercises(
        language: ExerciseLanguageCode,
        category: String?,
        equipment: [Int]?,
        limit: Int
    ) async throws -> [CatalogExercise] {
        var query: Query = db.collection(collectionName)

        if let category {
            query = query.whereField("category", isEqualTo: category)
        }

        if let equipment, let firstEquipment = equipment.first {
            query = query.whereField("equipment", arrayContains: firstEquipment)
        }

        query = query.limit(to: limit)

        let snapshot = try await query.getDocuments()
        let exercises = snapshot.documents.compactMap { doc -> CatalogExercise? in
            let exercise = parseCatalogExercise(from: doc, language: language)
            if let exercise { cache[exercise.id] = exercise }
            return exercise
        }

        #if DEBUG
        print("[FirestoreExerciseService] Fetched \(exercises.count) exercises (category: \(category ?? "all"))")
        #endif

        return exercises
    }

    func fetchExercise(id: String) async throws -> CatalogExercise? {
        if let cached = cache[id] {
            return cached
        }

        let doc = try await db.collection(collectionName).document(id).getDocument()

        guard doc.exists else { return nil }

        let exercise = parseCatalogExercise(from: doc, language: .portuguese)
        if let exercise { cache[exercise.id] = exercise }
        return exercise
    }

    func searchExercises(
        query: String,
        language: ExerciseLanguageCode,
        limit: Int
    ) async throws -> [CatalogExercise] {
        // Firestore doesn't support full-text search natively.
        // Use prefix matching on the name field.
        let normalizedQuery = query.lowercased()
            .folding(options: .diacriticInsensitive, locale: .current)

        let snapshot = try await db.collection(collectionName)
            .order(by: "name")
            .start(at: [normalizedQuery])
            .end(at: [normalizedQuery + "\u{f8ff}"])
            .limit(to: limit)
            .getDocuments()

        let exercises = snapshot.documents.compactMap { doc -> CatalogExercise? in
            let exercise = parseCatalogExercise(from: doc, language: language)
            if let exercise { cache[exercise.id] = exercise }
            return exercise
        }

        #if DEBUG
        print("[FirestoreExerciseService] Search '\(query)' → \(exercises.count) results")
        #endif

        return exercises
    }

    // MARK: - Parsing

    private func parseCatalogExercise(from doc: DocumentSnapshot, language: ExerciseLanguageCode) -> CatalogExercise? {
        guard let data = doc.data() else { return nil }

        let name = resolveExerciseName(from: data, documentId: doc.documentID, language: language)
        let description = resolveExerciseDescription(from: data, language: language)

        #if DEBUG
        if data["name"] == nil && data["name_\(language.code)"] == nil {
            print("[FirestoreExerciseService] ⚠️ No name field found for \(doc.documentID). Keys: \(data.keys.sorted())")
        }
        #endif

        return CatalogExercise(
            id: doc.documentID,
            name: name,
            description: description,
            category: data["category"] as? String,
            muscles: data["muscles"] as? [Int] ?? [],
            musclesSecondary: data["musclesSecondary"] as? [Int] ?? [],
            equipment: data["equipment"] as? [Int] ?? []
        )
    }

    /// Resolves the exercise name trying language-specific fields first, then generic name,
    /// then falls back to a human-readable form of the document ID.
    private func resolveExerciseName(from data: [String: Any], documentId: String, language: ExerciseLanguageCode) -> String {
        // Try language-specific name (e.g., "name_pt", "name_en")
        if let localizedName = data["name_\(language.code)"] as? String, !localizedName.isEmpty {
            return localizedName
        }
        // Try generic "name" field
        if let name = data["name"] as? String, !name.isEmpty {
            return name
        }
        // Fallback: convert document ID to readable name (e.g., "barbell_bench_press" → "Barbell Bench Press")
        return documentId
            .replacingOccurrences(of: "_", with: " ")
            .capitalized
    }

    /// Resolves the exercise description trying language-specific fields first.
    private func resolveExerciseDescription(from data: [String: Any], language: ExerciseLanguageCode) -> String? {
        if let localized = data["description_\(language.code)"] as? String, !localized.isEmpty {
            return localized
        }
        return data["description"] as? String
    }

    // MARK: - Cache

    func clearCache() {
        cache.removeAll()
    }
}

//
//  ExerciseImageCache.swift
//  FitToday
//
//  Created by Claude on 03/03/26.
//

import FirebaseStorage
import Foundation
import UIKit

/// Actor thread-safe para cache de imagens de exercícios do Firebase Storage.
/// Dois níveis: memória (NSCache) + disco (Caches/exercise_images/).
/// Evita downloads duplicados via `downloadTasks`.
actor ExerciseImageCache {
    static let shared = ExerciseImageCache()

    // MARK: - Memory Cache

    private let memoryCache = NSCache<NSString, UIImage>()

    // MARK: - Disk Cache

    private let diskDirectory: URL
    private let fileManager = FileManager.default

    // MARK: - Download Deduplication

    private var downloadTasks: [String: Task<UIImage?, Error>] = [:]

    // MARK: - Configuration

    private let maxDownloadSize: Int64 = 5 * 1024 * 1024 // 5MB
    private let compressionQuality: CGFloat = 0.85
    private let pruneThresholdDays: Int = 30

    // MARK: - Init

    private init() {
        let cacheDir = fileManager.urls(for: .cachesDirectory, in: .userDomainMask).first!
        self.diskDirectory = cacheDir.appendingPathComponent("exercise_images", isDirectory: true)

        // Create disk directory
        try? fileManager.createDirectory(at: diskDirectory, withIntermediateDirectories: true)

        // Configure memory cache limits
        memoryCache.countLimit = 100
        memoryCache.totalCostLimit = 50 * 1024 * 1024 // 50MB
    }

    // MARK: - Public API

    /// Fetches an exercise image. Checks memory → disk → Firebase Storage.
    /// - Parameters:
    ///   - exerciseId: The exercise identifier
    ///   - imageIndex: The image index (0 or 1)
    /// - Returns: UIImage if found, nil otherwise
    func image(for exerciseId: String, imageIndex: Int = 0) async -> UIImage? {
        let key = cacheKey(exerciseId: exerciseId, imageIndex: imageIndex)

        // 1. Memory cache
        if let cached = memoryCache.object(forKey: key as NSString) {
            return cached
        }

        // 2. Disk cache
        if let diskImage = loadFromDisk(key: key) {
            memoryCache.setObject(diskImage, forKey: key as NSString)
            return diskImage
        }

        // 3. Firebase Storage download (deduplicated)
        return await downloadFromStorage(exerciseId: exerciseId, imageIndex: imageIndex, key: key)
    }

    /// Prefetches images for all exercises in a workout using TaskGroup.
    /// Downloads image 0 and image 1 for each exercise in parallel.
    func prefetchWorkoutImages(exerciseIds: [String]) async {
        await withTaskGroup(of: Void.self) { group in
            for exerciseId in exerciseIds {
                group.addTask {
                    _ = await self.image(for: exerciseId, imageIndex: 0)
                }
                group.addTask {
                    _ = await self.image(for: exerciseId, imageIndex: 1)
                }
            }
        }
    }

    /// Removes cache files not accessed in the last 30 days.
    func pruneOldCache() {
        guard let files = try? fileManager.contentsOfDirectory(
            at: diskDirectory,
            includingPropertiesForKeys: [.contentAccessDateKey]
        ) else { return }

        let threshold = Calendar.current.date(byAdding: .day, value: -pruneThresholdDays, to: Date()) ?? Date()

        for file in files {
            guard let values = try? file.resourceValues(forKeys: [.contentAccessDateKey]),
                  let accessDate = values.contentAccessDate else {
                continue
            }
            if accessDate < threshold {
                try? fileManager.removeItem(at: file)
            }
        }

        #if DEBUG
        print("[ExerciseImageCache] pruneOldCache completed")
        #endif
    }

    /// Removes all cached exercise images from memory and disk.
    func clearCache() {
        memoryCache.removeAllObjects()

        guard let files = try? fileManager.contentsOfDirectory(at: diskDirectory, includingPropertiesForKeys: nil) else {
            return
        }
        for file in files {
            try? fileManager.removeItem(at: file)
        }

        #if DEBUG
        print("[ExerciseImageCache] Cache cleared")
        #endif
    }

    // MARK: - Private

    private func cacheKey(exerciseId: String, imageIndex: Int) -> String {
        "\(exerciseId)_\(imageIndex)"
    }

    private func diskPath(for key: String) -> URL {
        diskDirectory.appendingPathComponent("\(key).jpg")
    }

    private func loadFromDisk(key: String) -> UIImage? {
        let path = diskPath(for: key)
        guard fileManager.fileExists(atPath: path.path) else { return nil }

        // Update access time
        var mutableURL = path
        var values = URLResourceValues()
        values.contentAccessDate = Date()
        try? mutableURL.setResourceValues(values)

        guard let data = try? Data(contentsOf: path) else { return nil }
        return UIImage(data: data)
    }

    private func saveToDisk(image: UIImage, key: String) {
        guard let data = image.jpegData(compressionQuality: compressionQuality) else { return }
        let path = diskPath(for: key)
        try? data.write(to: path, options: .atomic)
    }

    private func downloadFromStorage(exerciseId: String, imageIndex: Int, key: String) async -> UIImage? {
        // Deduplicate: reuse existing download task if in progress
        if let existingTask = downloadTasks[key] {
            return try? await existingTask.value
        }

        let task = Task<UIImage?, Error> {
            let storage = Storage.storage()

            // Try media/ path first (primary), then thumbnail/ as fallback
            let paths = [
                "exercises/\(exerciseId)/media/\(imageIndex).jpg",
                "exercises/\(exerciseId)/thumbnail/\(imageIndex).webp"
            ]

            for storagePath in paths {
                let ref = storage.reference().child(storagePath)
                do {
                    let data = try await ref.data(maxSize: maxDownloadSize)
                    guard let image = UIImage(data: data) else { continue }

                    // Save to both caches
                    memoryCache.setObject(image, forKey: key as NSString)
                    saveToDisk(image: image, key: key)

                    return image
                } catch {
                    #if DEBUG
                    print("[ExerciseImageCache] Path not found: \(storagePath)")
                    #endif
                    continue
                }
            }

            #if DEBUG
            print("[ExerciseImageCache] No image found for exercise: \(exerciseId)")
            #endif
            return nil
        }

        downloadTasks[key] = task
        let result = try? await task.value
        downloadTasks[key] = nil
        return result
    }
}

